"""Multi-page static dashboard, regenerated by every scan/refresh.

Pages (written to publish/ for GitHub Pages, plus copies at project root):
  index.html   — overview: KPIs, equity curve, positions with exit levels
  radar.html   — what the bot is looking at next: candidates vs threshold,
                 budget state, exit map, watchlist/avoid, learning progress
  history.html — closed-trade P/L, weekly performance, decision log

Every panel carries its own "as of" stamp because the underlying data ages
at different rates (prices vs research vs ledger).
"""
import datetime as dt
import json
import os

from bot import config, ledger, market, risk
from bot.config import ROOT

