def _equity_svg(curve, deposited, w=640, h=190):
    if not curve:
        return '<div class="mut">no equity history yet</div>'
    pts = [e for _, e in curve]
    if len(pts) == 1:
        pts = pts * 2
    pad, padb = 10, 22
    lo = min(pts + ([deposited] if deposited else []))
    hi = max(pts + ([deposited] if deposited else []))
    if hi - lo < 1:
        lo, hi = lo - 1, hi + 1
    def x(i): return pad + i * (w - 2 * pad) / (len(pts) - 1)
    def y(v): return (h - padb) - (v - lo) * (h - padb - pad) / (hi - lo)
    coords = [(x(i), y(v)) for i, v in enumerate(pts)]
    line = _smooth_path(coords)
    area = line + " L {:.1f},{:.1f} L {:.1f},{:.1f} Z".format(
        coords[-1][0], h - padb, coords[0][0], h - padb)
    color = "#34D399" if (not deposited or pts[-1] >= deposited) else "#F87171"
    grid = "".join('<line x1="{p}" y1="{gy:.1f}" x2="{w2}" y2="{gy:.1f}" '
                   'stroke="#131D30" stroke-width="1"/>'.format(
                       p=pad, w2=w - pad, gy=(h - padb) - k * (h - padb - pad) / 4)
                   for k in range(1, 5))
    dep = ""
    if deposited:
        dep = ('<line x1="{p}" y1="{dy:.1f}" x2="{w2}" y2="{dy:.1f}" stroke="#7E8CA6" '
               'stroke-dasharray="4 4" opacity="0.6"/>').format(
            p=pad, w2=w - pad, dy=y(deposited))
    d0, d1 = curve[0][0][:10], curve[-1][0][:10]
    return ('<svg viewBox="0 0 {w} {h}" width="100%" role="img" aria-label="equity">'
            '<defs><linearGradient id="eq" x1="0" y1="0" x2="0" y2="1">'
            '<stop offset="0%" stop-color="{c}" stop-opacity="0.25"/>'
            '<stop offset="100%" stop-color="{c}" stop-opacity="0"/></linearGradient></defs>'
            '{grid}{dep}<path d="{area}" fill="url(#eq)"/>'
            '<path d="{line}" fill="none" stroke="{c}" stroke-width="2" '
            'stroke-linejoin="round" stroke-linecap="round"/>'
            '<circle cx="{cx:.1f}" cy="{cy:.1f}" r="3.5" fill="{c}"/>'
            '<circle cx="{cx:.1f}" cy="{cy:.1f}" r="6.5" fill="{c}" opacity="0.22"/>'
            '<text x="{p}" y="{h2}" fill="#5A6A87" font-size="9" font-family="Menlo,monospace">{d0}</text>'
            '<text x="{w2}" y="{h2}" fill="#5A6A87" font-size="9" text-anchor="end" font-family="Menlo,monospace">{d1}</text>'
            '<text x="{p}" y="{ty:.1f}" fill="#5A6A87" font-size="9" font-family="Menlo,monospace">${hi:,.0f}</text>'
            '<text x="{p}" y="{by:.1f}" fill="#5A6A87" font-size="9" font-family="Menlo,monospace">${lo:,.0f}</text>'
            '</svg>').format(w=w, h=h, c=color, grid=grid, dep=dep, area=area,
                             line=line, cx=x(len(pts) - 1), cy=y(pts[-1]), p=pad,
                             w2=w - pad, h2=h - 6, d0=d0, d1=d1,
                             ty=y(hi) + 10, by=y(lo) - 3, hi=hi, lo=lo)


def _sparkline(closes, cost=None, w=88, h=26):
    """Tiny inline SVG price line; green if last>=first, red otherwise. If cost
    is given, a faint dashed line marks the entry price."""
    if not closes or len(closes) < 2:
        return '<span class="mut" style="font-size:10px">no data</span>'
    lo, hi = min(closes), max(closes)
    if cost:
        lo, hi = min(lo, cost), max(hi, cost)
    rng = (hi - lo) or 1
    pad = 2
    def x(i): return pad + i * (w - 2 * pad) / (len(closes) - 1)
    def y(v): return (h - pad) - (v - lo) * (h - 2 * pad) / rng
    pts = " ".join("{:.1f},{:.1f}".format(x(i), y(v)) for i, v in enumerate(closes))
    up = closes[-1] >= closes[0]
    color = "#3DDC97" if up else "#FF7A70"
    cost_line = ""
    if cost:
        cost_line = ('<line x1="{p}" y1="{cy:.1f}" x2="{w2}" y2="{cy:.1f}" '
                     'stroke="#5C6B8C" stroke-width="0.7" stroke-dasharray="2 2" '
                     'opacity="0.7"/>').format(p=pad, w2=w - pad, cy=y(cost))
    return ('<svg viewBox="0 0 {w} {h}" width="{w}" height="{h}" '
            'style="vertical-align:middle">{cl}<polyline points="{pts}" fill="none" '
            'stroke="{c}" stroke-width="1.4"/>'
            '<circle cx="{cx:.1f}" cy="{cy:.1f}" r="1.8" fill="{c}"/></svg>').format(
        w=w, h=h, cl=cost_line, pts=pts, c=color, cx=x(len(closes) - 1),
        cy=y(closes[-1]))


def _period_stats(closed):
    """Realized P/L + averages for today / this week / this month."""
    today = dt.date.today()
    monday = today - dt.timedelta(days=today.weekday())
    month1 = today.replace(day=1)
    buckets = {"Day": [], "Week": [], "Month": [], "All time": []}
    for t in closed:
        d = dt.date.fromisoformat(t["ts"][:10])
        buckets["All time"].append(t)
        if d >= month1:
            buckets["Month"].append(t)
        if d >= monday:
            buckets["Week"].append(t)
        if d == today:
            buckets["Day"].append(t)
    rows = []
    for label, ts in buckets.items():
        wins = [t for t in ts if t["pnl"] > 0]
        losses = [t for t in ts if t["pnl"] <= 0]
        net = sum(t["pnl"] for t in ts)
        avg_w = sum(t["pct"] for t in wins) / len(wins) if wins else 0
        avg_l = sum(t["pct"] for t in losses) / len(losses) if losses else 0
        nc = "gain" if net >= 0 else "loss"
        rows.append(
            '<tr><td class="mono">{lb}</td><td class="mono r">{n}</td>'
            '<td class="mono r {nc}">{ns}${na:,.2f}</td>'
            '<td class="mono r gain">{aw}</td><td class="mono r loss">{al}</td></tr>'.format(
                lb=label, n=len(ts), nc=nc, ns="+" if net >= 0 else "−", na=abs(net),
                aw="+{:.1f}%".format(avg_w) if wins else "—",
                al="{:.1f}%".format(avg_l) if losses else "—"))
    return ('<table><tr><th>Window</th><th class="r">Trades</th><th class="r">Net P/L</th>'
            '<th class="r">Avg win</th><th class="r">Avg loss</th></tr>{}</table>'.format(
                "".join(rows)))


# WSB-flavoured captions, chosen by trade outcome
FAME_CAPS = [
    ("🚀", "TO THE MOON"), ("💎🙌", "diamond hands paid off"),
    ("🤑", "tendies secured"), ("📈", "absolute stonks"),
    ("🧠", "big brain play"), ("🍗", "fat tendies"),
]
SHAME_CAPS = [
    ("💀", "GUH"), ("📉", "bought the top, sold the bottom"),
    ("🧻🙌", "paper hands special"), ("🤡", "clown market got us"),
    ("🎒", "certified bagholder"), ("🔥", "this is fine"),
]


def _hall(closed):
    if not closed:
        return ('<div class="mut">no closed trades yet — the halls await their first '
                'legends and cautionary tales 🫡</div>')
    # Fame = actual winners only; Shame = actual losers only. A trade can never
    # appear in both, and a loss can never render as a green "win".
    winners = [t for t in closed if t["pnl"] > 0]
    losers = [t for t in closed if t["pnl"] < 0]
    best = sorted(winners, key=lambda t: t["pct"], reverse=True)[:3]
    worst = sorted(losers, key=lambda t: t["pct"])[:3]

    def card(t, caps, i):
        emoji, cap = caps[i % len(caps)]
        cls = "gain" if t["pnl"] >= 0 else "loss"   # colour by reality, not by hall
        held = ""
        try:
            held = "{}d".format((dt.date.fromisoformat(t["ts"][:10])
                                 - dt.date.fromisoformat(t["ts"][:10])).days)
        except Exception:
            pass
        return (
            '<div style="border:1px solid var(--line);border-radius:10px;padding:11px 13px;'
            'background:rgba(255,255,255,.02)">'
            '<div style="font-size:20px">{e}</div>'
            '<div class="mono" style="font-size:15px;font-weight:800;margin:3px 0">'
            '<span class="tk" style="color:var(--violet)">{tk}</span> '
            '<span class="{cls}">{ps}{pct:.1f}%</span></div>'
            '<div class="note" style="font-size:11px">{cap}</div>'
            '<div class="mono" style="font-size:10.5px;color:var(--dim);margin-top:3px">'
            '${b:.2f} → ${s:.2f} · {ns}${amt:,.2f}</div></div>').format(
            e=emoji, tk=t["ticker"], cls=cls, ps="+" if t["pct"] >= 0 else "",
            pct=t["pct"], cap=cap, b=t["buy"], s=t["sell"],
            ns="+" if t["pnl"] >= 0 else "−", amt=abs(t["pnl"]))

    empty = '<div class="mut" style="font-size:12px">none yet</div>'
    fame = "".join(card(t, FAME_CAPS, i) for i, t in enumerate(best)) or empty
    shame = "".join(card(t, SHAME_CAPS, i) for i, t in enumerate(worst)) or empty
    grid = ('display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px')
    return (
        '<div class="klabel" style="color:var(--gain)">🏆 Hall of Fame — biggest tendies ({nw} winner{ws})</div>'
        '<div style="{g}">{fame}</div>'
        '<div class="klabel" style="color:var(--loss);margin-top:14px">🤡 Hall of Shame — '
        'lessons in humility ({nl} loser{ls})</div><div style="{g}">{shame}</div>').format(
        g=grid, fame=fame, shame=shame, nw=len(winners), ws="" if len(winners) == 1 else "s",
        nl=len(losers), ls="" if len(losers) == 1 else "s")


def _smooth_path(pts):
    """Catmull-Rom → cubic bezier smoothing for a Robinhood-style curve."""
    if len(pts) < 3:
        return "M " + " L ".join("{:.1f},{:.1f}".format(*p) for p in pts)
    d = "M {:.1f},{:.1f}".format(*pts[0])
    for i in range(len(pts) - 1):
        p0 = pts[i - 1] if i > 0 else pts[0]
        p1, p2 = pts[i], pts[i + 1]
        p3 = pts[i + 2] if i + 2 < len(pts) else p2
        c1x = p1[0] + (p2[0] - p0[0]) / 6.0
        c1y = p1[1] + (p2[1] - p0[1]) / 6.0
        c2x = p2[0] - (p3[0] - p1[0]) / 6.0
        c2y = p2[1] - (p3[1] - p1[1]) / 6.0
        d += " C {:.1f},{:.1f} {:.1f},{:.1f} {:.1f},{:.1f}".format(c1x, c1y, c2x, c2y, p2[0], p2[1])
    return d


def _pnl_line(closed, w=560, h=170):
    """Robinhood-style cumulative realized-P/L curve: thin smoothed line, soft
    gradient fill, baseline at zero, endpoint dot. Replaces the old bar chart."""
    if not closed:
        return '<div class="mut">no closed trades yet — the line starts at your first sale</div>'
    ordered = sorted(closed, key=lambda t: t["ts"])
    cum, running = [0.0], 0.0
    for t in ordered:
        running += t["pnl"]
        cum.append(running)
    lo, hi = min(cum), max(cum)
    if hi - lo < 1:
        lo, hi = lo - 1, hi + 1
    pad_l, pad_r, pad_t, pad_b = 6, 6, 12, 16
    def x(i): return pad_l + i * (w - pad_l - pad_r) / (len(cum) - 1)
    def y(v): return (h - pad_b) - (v - lo) * (h - pad_b - pad_t) / (hi - lo)
    pts = [(x(i), y(v)) for i, v in enumerate(cum)]
    path = _smooth_path(pts)
    end_up = cum[-1] >= 0
    color = "#34D399" if end_up else "#F87171"
    zero_y = y(0)
    area = path + " L {:.1f},{:.1f} L {:.1f},{:.1f} Z".format(pts[-1][0], h - pad_b, pts[0][0], h - pad_b)
    return ('<svg viewBox="0 0 {w} {h}" width="100%" role="img" aria-label="cumulative P/L">'
            '<defs><linearGradient id="pl" x1="0" y1="0" x2="0" y2="1">'
            '<stop offset="0%" stop-color="{c}" stop-opacity="0.22"/>'
            '<stop offset="100%" stop-color="{c}" stop-opacity="0"/></linearGradient></defs>'
            '<line x1="{pl}" y1="{zy:.1f}" x2="{w2}" y2="{zy:.1f}" stroke="#2A3B5C" '
            'stroke-width="1" stroke-dasharray="3 3"/>'
            '<path d="{area}" fill="url(#pl)"/>'
            '<path d="{path}" fill="none" stroke="{c}" stroke-width="2" '
            'stroke-linejoin="round" stroke-linecap="round"/>'
            '<circle cx="{ex:.1f}" cy="{ey:.1f}" r="3.5" fill="{c}"/>'
            '<circle cx="{ex:.1f}" cy="{ey:.1f}" r="6" fill="{c}" opacity="0.25"/>'
            '<text x="{pl}" y="10" fill="#5A6A87" font-size="9" '
            'font-family="Menlo,monospace">cumulative realized P/L</text>'
            '<text x="{w2}" y="{ty:.1f}" fill="{c}" font-size="11" text-anchor="end" '
            'font-weight="700" font-family="Menlo,monospace">{end}</text></svg>').format(
        w=w, h=h, c=color, pl=pad_l, w2=w - pad_r, zy=zero_y, area=area, path=path,
        ex=pts[-1][0], ey=pts[-1][1], ty=max(pts[-1][1] - 8, 20),
        end=("+" if end_up else "−") + "${:,.2f}".format(abs(cum[-1])))


