def _extra_metrics(st):
    """Second-row stat strip: exposure, streak, avg hold, best/worst day, etc."""
    closed = st["closed"]
    positions = st["positions"]
    invested = sum((p["now"] or p["avg_cost"]) * p["shares"] for p in positions)
    exposure = (invested / st["equity"] * 100) if st["equity"] else 0

    # win/loss streak (most recent closed trades)
    streak, streak_kind = 0, None
    for t in reversed(closed):
        k = "W" if t["pnl"] > 0 else "L"
        if streak_kind is None:
            streak_kind = k
        if k == streak_kind:
            streak += 1
        else:
            break
    streak_txt = "—" if not closed else "{}{} {}".format(
        streak, streak_kind, "🔥" if streak_kind == "W" and streak >= 2
        else ("🧊" if streak_kind == "L" and streak >= 2 else ""))

    # P/L by calendar day → best/worst day
    by_day = {}
    for t in closed:
        by_day[t["ts"][:10]] = by_day.get(t["ts"][:10], 0) + t["pnl"]
    best_day = max(by_day.values()) if by_day else 0
    worst_day = min(by_day.values()) if by_day else 0

    total_ret = (st["equity"] / st["deposited"] - 1) * 100 if st["deposited"] else 0
    tot_cls = "gain" if total_ret >= 0 else "loss"

    tiles = [
        ("Total return", "{:+.1f}%".format(total_ret), tot_cls,
         "since first deposit"),
        ("Exposure", "{:.0f}%".format(exposure),
         "warn" if exposure > 90 else "mut", "invested vs cash"),
        ("Positions", "{}/{}".format(len(positions), st["cfg"]["buying"]["max_positions"]),
         "mut", "slots used"),
        ("Streak", streak_txt, "gain" if streak_kind == "W" else ("loss" if streak_kind == "L" else "mut"),
         "recent closes"),
        ("Best day", _money(best_day, sign=True), "gain", "single-day P/L"),
        ("Worst day", _money(worst_day, sign=True), "loss", "single-day P/L"),
    ]
    cells = "".join(
        '<div class="mtile"><div class="l">{l}</div><div class="v mono {c}">{v}</div>'
        '<div class="s">{s}</div></div>'.format(l=l, v=v, c=c, s=s)
        for l, v, c, s in tiles)
    return '<div class="mstrip">{}</div>'.format(cells)


def _kpis(st):
    unreal = sum(p["pl_usd"] or 0 for p in st["positions"])
    net = st["equity"] - st["deposited"] if st["deposited"] else 0.0
    realized = sum(t["pnl"] for t in st["closed"])
    def cls(v): return "gain" if v >= 0 else "loss"
    def sgn(v): return "+" if v >= 0 else "−"
    return """<div class="kpis">
<div class="kpi"><div class="l">Total equity</div><div class="v mono" title="${eqf:,.2f}">{eq}</div><div class="s">deposited {dep}</div></div>
<div class="kpi"><div class="l">Cash</div><div class="v mono" title="${cashf:,.2f}">{cash}</div><div class="s">{np} open position(s)</div></div>
<div class="kpi"><div class="l">Net P/L</div><div class="v mono {nc}">{net}</div><div class="s">vs deposits</div></div>
<div class="kpi"><div class="l">Unrealized</div><div class="v mono {uc}">{ur}</div><div class="s">open positions</div></div>
<div class="kpi"><div class="l">Realized</div><div class="v mono {rc}">{rl}</div><div class="s">{nt} closed trade(s)</div></div>
</div>""".format(eq=_money(st["equity"]), eqf=st["equity"], dep=_money(st["deposited"]),
                 cash=_money(st["cash"]), cashf=st["cash"], np=len(st["positions"]),
                 nc=cls(net), net=_money(net, sign=True),
                 uc=cls(unreal), ur=_money(unreal, sign=True),
                 rc=cls(realized), rl=_money(realized, sign=True),
                 nt=len(st["closed"]))


def _positions_panel(st):
    cfg, research = st["cfg"], st["research"]
    stop_pct = risk.dynamic_stop_pct(cfg, 0, research)
    tp = cfg["selling"]["take_profit_pct"]
    if not st["positions"]:
        inner = '<div class="mut" style="padding:20px 0;font-size:14px">flat — no open positions. Waiting for the next scan to deploy capital.</div>'
    else:
        rows = []
        for p in st["positions"]:
            hwm = max(p["high_water_mark"] or 0, p["now"] or 0)
            stop_lvl = hwm * (1 - stop_pct / 100)
            tp_lvl = p["avg_cost"] * (1 + tp / 100)
            cls = "mut" if p["pl_pct"] is None else ("gain" if p["pl_pct"] >= 0 else "loss")
            spark = _sparkline(market.price_series(p["ticker"]), cost=p["avg_cost"])
            pct_txt = "{:+.1f}%".format(p["pl_pct"]) if p["pl_pct"] is not None else "—"
            plu = "" if p["pl_usd"] is None else " ({}${:,.0f})".format(
                "+" if p["pl_usd"] >= 0 else "−", abs(p["pl_usd"]))
            rows.append(
                '<tr class="posrow" data-tkr="{t}" data-cost="{c}" data-sh="{sh}" '
                'data-stop="{stop}" data-hwm="{hwm}">'
                '<td class="mono" style="font-size:15px"><b>{t}</b></td><td>{spark}</td>'
                '<td class="mono r">{sh}</td><td class="mono r">${c:.2f}</td>'
                '<td class="mono r pos-now" style="font-size:15px">{n}</td>'
                '<td class="mono r pos-pl {cls}" style="font-size:15px;font-weight:700">{pct}{plu}</td>'
                '<td class="mono r loss pos-sell">${sl:.2f}</td>'
                '<td class="mono r gain">${tl:.2f}</td></tr>'.format(
                    t=p["ticker"], spark=spark, sh=_sh(p["shares"]), c=round(p["avg_cost"], 4),
                    stop=stop_pct, hwm=round(hwm, 4),
                    n="${:.2f}".format(p["now"]) if p["now"] else "—", cls=cls,
                    pct=pct_txt, plu=plu, sl=stop_lvl, tl=tp_lvl))
        inner = ('<table id="postbl" style="font-size:13.5px"><tr><th>Ticker</th><th>30d</th>'
                 '<th class="r">Qty</th><th class="r">Avg</th><th class="r">Now</th>'
                 '<th class="r">P/L</th><th class="r">Sells below</th><th class="r">Target</th></tr>'
                 '{}</table>'
                 '<div class="note" style="margin-top:8px">'
                 '<span class="ld" style="display:inline-block;width:7px;height:7px;border-radius:50%;'
                 'background:var(--gain);animation:pulse 1.6s infinite;margin-right:5px"></span>'
                 'Now &amp; P/L refresh live every 30s from the price feed. "Sells below" = '
                 'trailing stop (~{:.0f}%); target = +{:.0f}% take-profit.</div>'
                 '{}').format("".join(rows), stop_pct, tp, _positions_live_js())
    return panel("&#128200; Open positions", "live", inner)


FEED_URL = PRICES_URL.replace("prices.json", "feed.json")

# consistent colours for signal-contribution bars
SIGNAL_COLORS = {
    "insider": "#3EDDC5", "sector": "#A78BFA", "fundamentals": "#60A5FA",
    "news": "#FBBF24", "reddit": "#FB923C", "breakout": "#34D399",
    "earnings": "#F472B6", "events": "#F87171", "watchlist": "#94A3B8",
    "sector_bias": "#64748B", "insider_sentiment": "#22D3EE", "wildcard": "#E879F9",
}


def _catalyst_calendar(st):
    """Upcoming earnings for holdings + top candidates, urgency-coloured."""
    from bot.signals.technicals import days_to_earnings
    tickers = [p["ticker"] for p in st["positions"]] + \
              [c[0] for c in st["candidates"][:4]]
    held = {p["ticker"] for p in st["positions"]}
    rows = []
    for t in dict.fromkeys(tickers):
        d = days_to_earnings(t)
        if d is None or d > 45:
            continue
        date = (dt.date.today() + dt.timedelta(days=d)).strftime("%a %d %b")
        if d <= 2:
            cls, badge = "loss", ("&#9888; exit window" if t in held else "&#9888; too close to buy")
        elif d <= 7:
            cls, badge = "warn", "approaching"
        else:
            cls, badge = "mut", ""
        rows.append((d, '<tr><td class="mono"><b>{t}</b>{h}</td>'
                        '<td class="mono r {c}">{d}d</td><td class="mono r">{dt}</td>'
                        '<td class="note {c}">{b}</td></tr>'.format(
                            t=t, h=' <span class="chip tick" style="font-size:9px">held</span>' if t in held else "",
                            c=cls, d=d, dt=date, b=badge)))
    rows.sort(key=lambda x: x[0])
    if not rows:
        inner = ('<div class="mut">no earnings inside 45 days for holdings or '
                 'top candidates — no binary events on the radar</div>')
    else:
        inner = ('<table><tr><th>Ticker</th><th class="r">In</th><th class="r">Date</th>'
                 '<th></th></tr>{}</table>'
                 '<div class="note" style="margin-top:8px">Bot exits positions 1 day '
                 'before earnings and won\'t buy within 2 days of a print.</div>'
                 ).format("".join(r for _, r in rows))
    return panel("&#128197; Catalyst calendar", "earnings dates", inner)


def _sector_meter(st):
    """Sector allocation of the book: stacked bar + concentration warnings."""
    if not st["positions"]:
        return panel("&#127959; Sector allocation", "book",
                     '<div class="mut">flat — nothing allocated</div>')
    cfg = st["cfg"]
    by_sector = {}
    for p in st["positions"]:
        sec = (market.ticker_info(p["ticker"]).get("sector")) or "Unknown"
        by_sector.setdefault(sec, {"val": 0.0, "n": 0})
        by_sector[sec]["val"] += (p["now"] or p["avg_cost"]) * p["shares"]
        by_sector[sec]["n"] += 1
    total = sum(v["val"] for v in by_sector.values()) or 1
    palette = ["#3EDDC5", "#A78BFA", "#60A5FA", "#FBBF24", "#F472B6", "#34D399",
               "#FB923C", "#22D3EE", "#94A3B8"]
    segs, chips, warns = [], [], []
    max_n = cfg["risk"]["max_sector_positions"]
    for i, (sec, v) in enumerate(sorted(by_sector.items(), key=lambda kv: -kv[1]["val"])):
        pct = v["val"] / total * 100
        color = palette[i % len(palette)]
        segs.append('<i style="width:{:.1f}%;background:{}" title="{} {:.0f}%"></i>'.format(
            pct, color, sec, pct))
        chips.append('<span class="chip" style="border-color:{c}55;color:{c}">{s} '
                     '{p:.0f}% ({n})</span>'.format(c=color, s=sec, p=pct, n=v["n"]))
        if pct > 40:
            warns.append("{} is {:.0f}% of the book".format(sec, pct))
        if v["n"] >= max_n:
            warns.append("{} at position cap ({}/{})".format(sec, v["n"], max_n))
    warn_html = ""
    if warns:
        warn_html = ('<div class="note warn" style="margin-top:8px">&#9888; ' +
                     " &middot; ".join(warns) + "</div>")
    inner = ('<style>.secbar{display:flex;height:14px;border-radius:7px;overflow:hidden;'
             'margin-bottom:10px}.secbar i{display:block;height:14px}</style>'
             '<div class="secbar">' + "".join(segs) + '</div>'
             '<div class="chips">' + "".join(chips) + "</div>" + warn_html)
    return panel("&#127959; Sector allocation", "book", inner)


def _signal_bar(parts, width=140):
    """Stacked contribution bar for one candidate's score parts."""
    total = sum(abs(v) for v in parts.values()) or 1
    segs = []
    for k, v in sorted(parts.items(), key=lambda kv: -abs(kv[1])):
        if not v:
            continue
        c = SIGNAL_COLORS.get(k, "#7E8CA6")
        w = abs(v) / total * 100
        op = "1" if v > 0 else "0.35"
        segs.append('<i style="width:{:.1f}%;background:{};opacity:{}" '
                    'title="{} {:+.2f}"></i>'.format(w, c, op, k, v))
    return ('<div class="sigbar" style="width:{}px">'.format(width) +
            "".join(segs) + "</div>")


def _signal_legend():
    return ('<div class="chips" style="margin-top:8px">' + "".join(
        '<span class="chip" style="font-size:10px;border-color:{c}44;color:{c}">{k}</span>'.format(
            c=c, k=k) for k, c in SIGNAL_COLORS.items()
        if k in ("insider", "sector", "fundamentals", "news", "reddit",
                 "breakout", "earnings", "events")) + "</div>")


def _drawdown_ribbon(st):
    """Thin underwater ribbon: % below equity peak over time + current value."""
    curve = st["curve"]
    if len(curve) < 3:
        return ""
    peak, dd = 0.0, []
    for _, e in curve:
        peak = max(peak, e)
        dd.append((1 - e / peak) * 100 if peak else 0)
    cur = dd[-1]
    worst = max(dd)
    w, h, pad = 900, 46, 2
    def x(i): return pad + i * (w - 2 * pad) / (len(dd) - 1)
    def y(v): return pad + (v / max(worst, 1)) * (h - 2 * pad)
    pts = " ".join("{:.1f},{:.1f}".format(x(i), y(v)) for i, v in enumerate(dd))
    area = "{:.1f},{} {} {:.1f},{}".format(x(0), pad, pts, x(len(dd) - 1), pad)
    cls = "gain" if cur < 3 else ("warn" if cur < 8 else "loss")
    halt = st["cfg"]["risk"]["drawdown_halt_pct"]
    return ('<div class="panel" style="padding:10px 16px"><div class="ph" style="margin-bottom:4px">'
            '<h2>Underwater ribbon</h2><span class="asof">drawdown from peak &middot; '
            'buying halts at {halt}%</span></div>'
            '<div style="display:flex;align-items:center;gap:14px">'
            '<div class="mono {cls}" style="font-size:19px;font-weight:700;white-space:nowrap">'
            '&minus;{cur:.1f}%</div>'
            '<svg viewBox="0 0 {w} {h}" width="100%" height="{h}" preserveAspectRatio="none">'
            '<polygon points="{area}" fill="rgba(230,80,75,0.25)"/>'
            '<polyline points="{pts}" fill="none" stroke="#F87171" stroke-width="1.3"/>'
            '</svg></div></div>').format(
        halt=halt, cls=cls, cur=cur, w=w, h=h, area=area, pts=pts)


